  3→/// Today's session list — the hero view of Pablo Companion.
  4→///
  5→/// Shows scheduled sessions, provides Start Session + Quick Start flows,
  6→/// and polls the backend every 30 seconds to keep statuses fresh.
  7→struct DayView: View {
  8→    var sessionVM: SessionViewModel
  9→    var patients: [Patient]
 10→    var isLoadingPatients: Bool
 11→    @Binding var patientSearchText: String
 12→    var recordingState: RecordingUIState = .idle
 13→    var recordingDuration: TimeInterval = 0
 14→    var onStartSession: ((Session) -> Void)?
 15→    var onQuickStart: ((Patient) -> Void)?
 16→    var onStopRecording: (() -> Void)?
 17→
 18→    @State private var lastRefreshDate = Date()
 19→    @State private var showingQuickStart = false
 20→
 21→    var body: some View {
 22→        VStack(spacing: 0) {
 23→            header
 24→            if recordingState != .idle {
 25→                recordingBanner
 26→            }
 27→            Divider()
 28→            content
 29→        }
 30→        .background(Color.pabloCream)
 31→        .task {
 32→            await sessionVM.loadTodaySessions()
 33→            lastRefreshDate = Date()
 34→        }
 35→        .task { await pollSessions() }
 36→        .sheet(isPresented: $showingQuickStart) {
 37→            QuickStartSheet(
 38→                patients: patients,
 39→                isLoading: isLoadingPatients,
 40→                searchText: $patientSearchText,
 41→                onSelect: { patient in onQuickStart?(patient) }
 42→            )
 43→        }
 44→    }
 45→
 46→    // MARK: - Header
 47→
 48→    private var header: some View {
 49→        HStack {
 50→            VStack(alignment: .leading, spacing: 4) {
 51→                Text(greeting)
 52→                    .font(.pabloDisplay(24))
 53→                    .foregroundStyle(Color.pabloBrownDeep)
 54→                Text(formattedDate)
 55→                    .font(.pabloBody(14))
 56→                    .foregroundStyle(Color.pabloBrownSoft)
 57→            }
 58→            Spacer()
 59→            if sessionVM.isLoading {
 60→                ProgressView().controlSize(.small)
 61→            }
 62→            sessionCountBadge
 63→            quickStartButton
 64→        }
 65→        .padding(.horizontal, 20)
 66→        .padding(.vertical, 16)
 67→    }
 68→
 69→    private var sessionCountBadge: some View {
 70→        Group {
 71→            if !sessionVM.todaySessions.isEmpty {
 72→                Text("\(sessionVM.todaySessions.count)")
 73→                    .font(.pabloBody(12))
 74→                    .foregroundStyle(Color.pabloBrownDeep)
 75→                    .frame(width: 24, height: 24)
 76→                    .background(Color.pabloHoney.opacity(0.2))
 77→                    .clipShape(Circle())
 78→            }
 79→        }
 80→    }
 81→
 82→    private var quickStartButton: some View {
 83→        Button { showingQuickStart = true } label: {
 84→            Label("Quick Start", systemImage: "plus.circle.fill")
 85→                .font(.pabloBody(13))
 86→                .foregroundStyle(Color.pabloBrownDeep)
 87→                .padding(.horizontal, 10)
 88→                .padding(.vertical, 6)
 89→                .background(Color.pabloHoney)
 90→                .clipShape(RoundedRectangle(cornerRadius: 8))
 91→        }
 92→        .buttonStyle(.plain)
 93→    }
 94→
 95→    // MARK: - Recording Banner
 96→
 97→    private var recordingBanner: some View {
 98→        HStack(spacing: 12) {
 99→            Circle()
100→                .fill(Color.pabloSage)
101→                .frame(width: 10, height: 10)
102→                .overlay(
103→                    Circle()
104→                        .fill(Color.pabloSage.opacity(0.4))
105→                        .frame(width: 18, height: 18)
106→                )
107→
108→            Text(recordingState == .paused ? "Paused" : "Recording")
109→                .font(.pabloBody(14))
110→                .fontWeight(.medium)
111→                .foregroundStyle(Color.pabloBrownDeep)
112→
113→            Text(formattedDuration(recordingDuration))
114→                .font(.system(size: 14, design: .monospaced))
115→                .foregroundStyle(Color.pabloBrownSoft)
116→
117→            Spacer()
118→
119→            Button {
120→                onStopRecording?()
121→            } label: {
122→                Label("Stop", systemImage: "stop.fill")
123→                    .font(.pabloBody(13))
124→                    .foregroundStyle(.white)
125→                    .padding(.horizontal, 12)
126→                    .padding(.vertical, 6)
127→                    .background(Color.pabloError)
128→                    .clipShape(RoundedRectangle(cornerRadius: 8))
129→            }
130→            .buttonStyle(.plain)
131→        }
132→        .padding(.horizontal, 20)
133→        .padding(.vertical, 10)
134→        .background(Color.pabloSage.opacity(0.1))
135→    }
136→
137→    private func formattedDuration(_ duration: TimeInterval) -> String {
138→        let minutes = Int(duration) / 60
139→        let seconds = Int(duration) % 60
140→        return String(format: "%d:%02d", minutes, seconds)
141→    }
142→
143→    // MARK: - Content
144→
145→    @ViewBuilder
146→    private var content: some View {
147→        if sessionVM.isLoading, sessionVM.todaySessions.isEmpty {
148→            loadingState
149→        } else if sessionVM.todaySessions.isEmpty {
150→            emptyState
151→        } else {
152→            sessionList
153→        }
154→    }
155→
156→    private var sessionList: some View {
157→        VStack(spacing: 0) {
158→            List {
159→                ForEach(sessionVM.todaySessions, id: \.id) { session in
160→                    SessionRowView(session: session) {
161→                        onStartSession?(session)
162→                    }
163→                    .pabloListRowStyle()
164→                    .padding(.vertical, 2)
165→                }
166→            }
167→            .pabloListStyle()
168→
169→            lastUpdatedLabel
170→        }
171→    }
172→
173→    private var lastUpdatedLabel: some View {
174→        Text("Updated \(lastRefreshDate, format: .relative(presentation: .named))")
175→            .font(.pabloBody(11))
176→            .foregroundStyle(.secondary)
177→            .frame(maxWidth: .infinity)
178→            .padding(.vertical, 6)
179→    }
180→
181→    // MARK: - Empty state
182→
183→    private var emptyState: some View {
184→        VStack(spacing: 20) {
185→            Spacer()
186→            ZStack {
187→                Circle()
188→                    .fill(Color.pabloHoney.opacity(0.12))
189→                    .frame(width: 80, height: 80)
190→                Image(systemName: "calendar")
191→                    .font(.system(size: 32, weight: .light))
192→                    .foregroundStyle(Color.pabloHoney)
193→            }
194→            Text("No sessions today")
195→                .font(.pabloDisplay(20))
196→                .foregroundStyle(Color.pabloBrownDeep)
197→            Text("Your schedule is clear.\nSessions scheduled in Pablo will appear here.")
198→                .font(.pabloBody(14))
199→                .foregroundStyle(Color.pabloBrownSoft)
200→                .multilineTextAlignment(.center)
201→                .lineSpacing(4)
202→            Spacer()
203→        }
204→        .frame(maxWidth: .infinity)
205→        .padding(32)
206→    }
207→
208→    // MARK: - Loading state
209→
210→    private var loadingState: some View {
211→        VStack(spacing: 12) {
212→            Spacer()
213→            ProgressView()
214→                .controlSize(.large)
215→                .tint(Color.pabloHoney)
216→            Text("Loading sessions...")
217→                .font(.pabloBody(14))
218→                .foregroundStyle(Color.pabloBrownSoft)
219→            Spacer()
220→        }
221→        .frame(maxWidth: .infinity)
222→    }
223→
224→    // MARK: - Polling
225→
226→    private func pollSessions() async {
227→        while !Task.isCancelled {
228→            try? await Task.sleep(for: .seconds(30))
229→            guard !Task.isCancelled else { break }
230→            await sessionVM.loadTodaySessions()
231→            lastRefreshDate = Date()
232→        }
233→    }
234→
235→    // MARK: - Helpers
236→
237→    private var formattedDate: String {
238→        let formatter = DateFormatter()
239→        formatter.dateFormat = "EEEE, MMMM d"
240→        return formatter.string(from: Date())
241→    }
242→
243→    private var greeting: String {
244→        let hour = Calendar.current.component(.hour, from: Date())
245→        switch hour {
246→        case 0 ..< 12: return "Good morning"
247→        case 12 ..< 17: return "Good afternoon"
248→        default: return "Good evening"
249→        }
250→    }
251→}
252→
253→// MARK: - Preview
254→
255→#Preview("With sessions") {
256→    DayView(
257→        sessionVM: {
258→            let vm = SessionViewModel()
259→            vm.todaySessions = [PreviewData.scheduled, PreviewData.inProgress]
260→            return vm
261→        }(),
262→        patients: [],
263→        isLoadingPatients: false,
264→        patientSearchText: .constant("")
265→    )
266→}
267→
268→#Preview("Empty") {
269→    DayView(
270→        sessionVM: SessionViewModel(),
271→        patients: [],
272→        isLoadingPatients: false,
273→        patientSearchText: .constant("")
274→    )
275→}
