 1→import Foundation
 2→import os
 3→
 4→/// Manages uploading recordings to the sample backend.
 5→@MainActor
 6→@Observable
 7→final class UploadViewModel {
 8→    var backendURL = "http://localhost:8000" {
 9→        didSet {
10→            if URLValidator.validateScheme(backendURL) == nil {
11→                let token = apiClient.getToken
12→                apiClient = APIClient(baseURL: backendURL)
13→                apiClient.getToken = token
14→            }
15→        }
16→    }
17→
18→    var isBackendReachable = false
19→    var uploadProgress: [UUID: Double] = [:]
20→    var uploadingRecordingIDs: Set<UUID> = []
21→    var errorMessage: String?
22→    var showError = false
23→
24→    private var apiClient: APIClient
25→    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "UploadViewModel")
26→
27→    init() {
28→        self.apiClient = APIClient()
29→    }
30→
31→    /// Configures the API client with a token provider for authenticated uploads.
32→    func configureAuth(getToken: @escaping @Sendable () async throws -> String) {
33→        apiClient.getToken = getToken
34→    }
35→
36→    func checkBackendHealth() async {
37→        do {
38→            isBackendReachable = try await apiClient.healthCheck()
39→            logger.info("Backend health check: \(self.isBackendReachable ? "OK" : "FAILED")")
40→        } catch {
41→            isBackendReachable = false
42→            logger.warning("Backend unreachable: \(error.localizedDescription)")
43→        }
44→    }
45→
46→    func uploadRecording(
47→        _ recording: LocalRecording,
48→        onComplete: @escaping (UUID) -> Void
49→    ) async {
50→        guard !uploadingRecordingIDs.contains(recording.id) else { return }
51→
52→        uploadingRecordingIDs.insert(recording.id)
53→        uploadProgress[recording.id] = 0.0
54→        logger.info("Starting upload for \(recording.id)")
55→
56→        do {
57→            _ = try await apiClient.uploadRecording(
58→                fileURL: recording.fileURL
59→            ) { [weak self] progress in
60→                Task { @MainActor in
61→                    self?.uploadProgress[recording.id] = progress
62→                }
63→            }
64→
65→            uploadProgress[recording.id] = 1.0
66→            uploadingRecordingIDs.remove(recording.id)
67→            onComplete(recording.id)
68→            logger.info("Upload complete for \(recording.id)")
69→        } catch {
70→            uploadingRecordingIDs.remove(recording.id)
71→            uploadProgress.removeValue(forKey: recording.id)
72→            logger.error("Upload failed for \(recording.id): \(error.localizedDescription)")
73→            errorMessage = "Upload failed: \(error.localizedDescription)"
74→            showError = true
75→        }
76→    }
77→}
