  1→import AuthenticationServices
  2→import Foundation
  3→import os
  4→import SwiftUI
  5→
  6→/// Manages authentication state via ASWebAuthenticationSession and Firebase token refresh.
  7→@MainActor
  8→@Observable
  9→final class AuthViewModel {
 10→    // MARK: - Auth State
 11→
 12→    enum AuthState: Equatable {
 13→        case unauthenticated
 14→        case authenticating
 15→        case authenticated(email: String)
 16→        case tokenExpired
 17→    }
 18→
 19→    var authState: AuthState = .unauthenticated
 20→    var errorMessage: String?
 21→
 22→    @ObservationIgnored
 23→    @AppStorage("authServerURL") var authServerURL = "http://localhost:3000"
 24→
 25→    @ObservationIgnored
 26→    @AppStorage("backendAPIURL") var backendAPIURL = "http://localhost:8000"
 27→
 28→    @ObservationIgnored
 29→    @AppStorage("tokenExpiry") private var tokenExpiryTimestamp: Double = 0
 30→
 31→    /// Convenience accessor for the email when authenticated.
 32→    var authenticatedEmail: String {
 33→        if case let .authenticated(email) = authState {
 34→            return email
 35→        }
 36→        return ""
 37→    }
 38→
 39→    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "AuthViewModel")
 40→
 41→    // MARK: - Init
 42→
 43→    init() {
 44→        restoreAuthState()
 45→    }
 46→
 47→    // MARK: - Sign In
 48→
 49→    func signIn() {
 50→        guard let url = buildAuthURL() else {
 51→            errorMessage = "Invalid auth server URL."
 52→            return
 53→        }
 54→
 55→        authState = .authenticating
 56→        errorMessage = nil
 57→
 58→        // Launch from a file-scope free function so the completion closure
 59→        // is NOT defined in a @MainActor context. (swiftlang/swift#75453)
 60→        launchWebAuthSession(url: url, viewModel: self)
 61→        logger.info("ASWebAuthenticationSession started")
 62→    }
 63→
 64→    // MARK: - Sign Out
 65→
 66→    func signOut() {
 67→        KeychainManager.deleteAll()
 68→        tokenExpiryTimestamp = 0
 69→        authState = .unauthenticated
 70→        errorMessage = nil
 71→        logger.info("User signed out")
 72→    }
 73→
 74→    // MARK: - Token Access
 75→
 76→    /// Returns a valid ID token, refreshing if needed. Throws on failure.
 77→    func getValidToken() async throws -> String {
 78→        guard let idToken = KeychainManager.getToken(forKey: .idToken) else {
 79→            authState = .tokenExpired
 80→            throw TokenError.noToken
 81→        }
 82→
 83→        // Refresh if within 5-minute buffer of expiry
 84→        let expiryDate = Date(timeIntervalSince1970: tokenExpiryTimestamp)
 85→        if Date().addingTimeInterval(5 * 60) >= expiryDate {
 86→            return try await refreshToken()
 87→        }
 88→
 89→        return idToken
 90→    }
 91→
 92→    // MARK: - Private
 93→
 94→    private func restoreAuthState() {
 95→        guard let idToken = KeychainManager.getToken(forKey: .idToken),
 96→              let email = KeychainManager.getToken(forKey: .userEmail)
 97→        else {
 98→            authState = .unauthenticated
 99→            return
100→        }
101→
102→        // Restore auth server URL from Keychain
103→        if let savedURL = KeychainManager.getToken(forKey: .authServerURL) {
104→            authServerURL = savedURL
105→        }
106→
107→        let expiryDate = Date(timeIntervalSince1970: tokenExpiryTimestamp)
108→        if Date().addingTimeInterval(5 * 60) >= expiryDate {
109→            // Token expired or close to it — check if we can refresh
110→            if KeychainManager.getToken(forKey: .refreshToken) != nil {
111→                authState = .authenticated(email: email)
112→                logger.info("Restored auth state for \(email) (token needs refresh)")
113→            } else {
114→                authState = .tokenExpired
115→                logger.info("Token expired and no refresh token available")
116→            }
117→        } else {
118→            authState = .authenticated(email: email)
119→            logger.info("Restored auth state for \(email), token valid")
120→        }
121→
122→        // Also update expiry from JWT if we have a fresh token
123→        if let expiry = extractExpiry(from: idToken) {
124→            tokenExpiryTimestamp = expiry.timeIntervalSince1970
125→        }
126→    }
127→
128→    private func buildAuthURL() -> URL? {
129→        if let error = URLValidator.validateScheme(authServerURL) {
130→            errorMessage = error
131→            return nil
132→        }
133→        let base = authServerURL.trimmingCharacters(in: .init(charactersIn: "/"))
134→        let redirectURI = "therapyrecorder://callback"
135→        return URL(string: "\(base)/native-auth?redirect_uri=\(redirectURI)")
136→    }
137→
138→    func handleAuthCallback(callbackURL: URL?, error: (any Error)?) {
139→        if let error {
140→            if (error as NSError).code == ASWebAuthenticationSessionError.canceledLogin.rawValue {
141→                logger.info("User cancelled sign in")
142→                authState = .unauthenticated
143→                return
144→            }
145→            logger.error("Auth error: \(error.localizedDescription)")
146→            errorMessage = error.localizedDescription
147→            authState = .unauthenticated
148→            return
149→        }
150→
151→        guard let callbackURL,
152→              let components = URLComponents(url: callbackURL, resolvingAgainstBaseURL: false),
153→              let queryItems = components.queryItems
154→        else {
155→            errorMessage = "Invalid callback URL."
156→            authState = .unauthenticated
157→            return
158→        }
159→
160→        let params = Dictionary(uniqueKeysWithValues: queryItems.compactMap { item in
161→            item.value.map { (item.name, $0) }
162→        })
163→
164→        guard let idToken = params["id_token"],
165→              let refreshToken = params["refresh_token"]
166→        else {
167→            errorMessage = "Missing tokens in callback."
168→            authState = .unauthenticated
169→            return
170→        }
171→
172→        // Store tokens and auth server URL for session restore
173→        KeychainManager.saveToken(idToken, forKey: .idToken)
174→        KeychainManager.saveToken(refreshToken, forKey: .refreshToken)
175→        KeychainManager.saveToken(authServerURL, forKey: .authServerURL)
176→
177→        // Extract email from JWT
178→        let email = extractEmail(from: idToken) ?? params["email"] ?? "Unknown"
179→        KeychainManager.saveToken(email, forKey: .userEmail)
180→
181→        // Extract and store expiry
182→        if let expiry = extractExpiry(from: idToken) {
183→            tokenExpiryTimestamp = expiry.timeIntervalSince1970
184→        }
185→
186→        authState = .authenticated(email: email)
187→        errorMessage = nil
188→        logger.info("Signed in as \(email)")
189→    }
190→
191→    private func refreshToken() async throws -> String {
192→        guard let refreshToken = KeychainManager.getToken(forKey: .refreshToken) else {
193→            authState = .tokenExpired
194→            throw TokenError.noRefreshToken
195→        }
196→
197→        guard let firebaseAPIKey = KeychainManager.getToken(forKey: .firebaseAPIKey),
198→              !firebaseAPIKey.isEmpty
199→        else {
200→            throw TokenError.noAPIKey
201→        }
202→
203→        let refresher = TokenRefresher(apiKey: firebaseAPIKey)
204→        do {
205→            let response = try await refresher.refresh(using: refreshToken)
206→
207→            KeychainManager.saveToken(response.idToken, forKey: .idToken)
208→            KeychainManager.saveToken(response.refreshToken, forKey: .refreshToken)
209→            tokenExpiryTimestamp = Date().addingTimeInterval(Double(response.expiresIn)).timeIntervalSince1970
210→
211→            // Update email if it changed
212→            if let email = extractEmail(from: response.idToken) {
213→                KeychainManager.saveToken(email, forKey: .userEmail)
214→                authState = .authenticated(email: email)
215→            }
216→
217→            return response.idToken
218→        } catch let refreshError as TokenRefresher.RefreshError {
219→            authState = .tokenExpired
220→            throw refreshError
221→        }
222→    }
223→
224→    // MARK: - JWT Helpers
225→
226→    private let jwtDecoder = JWTDecoder()
227→
228→    func extractExpiry(from idToken: String) -> Date? {
229→        jwtDecoder.extractExpiry(from: idToken)
230→    }
231→
232→    private func extractEmail(from idToken: String) -> String? {
233→        jwtDecoder.extractEmail(from: idToken)
234→    }
235→}
236→
237→// MARK: - Errors
238→
239→enum TokenError: LocalizedError {
240→    case noToken
241→    case noRefreshToken
242→    case noAPIKey
243→
244→    var errorDescription: String? {
245→        switch self {
246→        case .noToken:
247→            "No authentication token found. Please sign in."
248→        case .noRefreshToken:
249→            "Session expired. Please sign in again."
250→        case .noAPIKey:
251→            "Firebase API key not configured."
252→        }
253→    }
254→}
