256→// MARK: - JWT Decoder
257→
258→struct JWTDecoder {
259→    func decodePayload(_ jwt: String) -> [String: Any]? {
260→        let parts = jwt.split(separator: ".")
261→        guard parts.count >= 2 else { return nil }
262→        var base64 = String(parts[1])
263→            .replacingOccurrences(of: "-", with: "+")
264→            .replacingOccurrences(of: "_", with: "/")
265→        let remainder = base64.count % 4
266→        if remainder > 0 { base64 += String(repeating: "=", count: 4 - remainder) }
267→        guard let data = Data(base64Encoded: base64),
268→              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any]
269→        else { return nil }
270→        return json
271→    }
272→
273→    func extractExpiry(from jwt: String) -> Date? {
274→        guard let payload = decodePayload(jwt),
275→              let exp = payload["exp"] as? TimeInterval
276→        else { return nil }
277→        return Date(timeIntervalSince1970: exp)
278→    }
279→
280→    func extractEmail(from jwt: String) -> String? {
281→        decodePayload(jwt)?["email"] as? String
282→    }
283→}
