285→// MARK: - Web Auth Session Launcher
286→
287→/// Sendable wrapper for weak references that cross isolation boundaries.
288→private struct WeakRef<T: AnyObject>: @unchecked Sendable {
289→    weak var value: T?
290→}
291→
292→/// Launches ASWebAuthenticationSession from a nonisolated (file-scope) context
293→/// so the completion closure doesn't inherit @MainActor isolation and crash
294→/// when the framework calls back on an XPC thread. (swiftlang/swift#75453)
295→private func launchWebAuthSession(url: URL, viewModel: AuthViewModel) {
296→    let ref = WeakRef(value: viewModel)
297→    // This function is always called from MainActor but must stay nonisolated
298→    // (see above). Use assumeIsolated just for the NSObject.init() call.
299→    let contextProvider = MainActor.assumeIsolated { WebAuthContextProvider() }
300→    let session = ASWebAuthenticationSession(
301→        url: url,
302→        callbackURLScheme: "therapyrecorder"
303→    ) { callbackURL, error in
304→        Task { @MainActor in
305→            ref.value?.handleAuthCallback(callbackURL: callbackURL, error: error)
306→        }
307→    }
308→    session.presentationContextProvider = contextProvider
309→    session.prefersEphemeralWebBrowserSession = false
310→    _ = contextProvider
311→    session.start()
312→}
313→
314→// MARK: - ASWebAuthenticationPresentationContextProviding
315→
316→private final class WebAuthContextProvider: NSObject, ASWebAuthenticationPresentationContextProviding {
317→    func presentationAnchor(for _: ASWebAuthenticationSession) -> ASPresentationAnchor {
318→        // swiftlint:disable:next force_unwrapping
319→        NSApplication.shared.keyWindow ?? NSApplication.shared.windows.first!
320→    }
321→}
