 51→// MARK: - ModelError
 52→
 53→enum ModelError: Error, LocalizedError {
 54→    case notFound(WhisperModelPreset)
 55→    case downloadFailed(String)
 56→
 57→    var errorDescription: String? {
 58→        switch self {
 59→        case let .notFound(preset):
 60→            "Model file not found for \(preset.displayName) preset (\(preset.modelFileName))"
 61→        case let .downloadFailed(reason):
 62→            "Model download failed: \(reason)"
 63→        }
 64→    }
