 67→// MARK: - ModelManager
 68→
 69→/// Manages Whisper model files for local transcription.
 70→/// Resolves model paths from the app's Application Support directory or the app bundle.
 71→@MainActor
 72→final class ModelManager: ObservableObject {
 73→    static let shared = ModelManager()
 74→
 75→    @Published var downloadProgress: [WhisperModelPreset: Double] = [:]
 76→    @Published var downloadingPresets: Set<WhisperModelPreset> = []
 77→
 78→    private let fileManager = FileManager.default
 79→    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "ModelManager")
 80→
 81→    private var modelsDirectory: URL {
 82→        let appSupport = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask)[0]
 83→        let dir = appSupport
 84→            .appendingPathComponent("PabloCompanion", isDirectory: true)
 85→            .appendingPathComponent("Models", isDirectory: true)
 86→        try? fileManager.createDirectory(at: dir, withIntermediateDirectories: true)
 87→        return dir
 88→    }
 89→
 90→    /// Returns the URL to the model file for the given preset.
 91→    /// Checks the models directory first, then the app bundle.
 92→    func modelURL(for preset: WhisperModelPreset) throws -> URL {
 93→        // Check Application Support models directory first
 94→        let cachedURL = modelsDirectory.appendingPathComponent(preset.modelFileName)
 95→        if fileManager.fileExists(atPath: cachedURL.path) {
 96→            logger.debug("Found model in cache: \(preset.modelFileName)")
 97→            return cachedURL
 98→        }
 99→
100→        // Fall back to app bundle
101→        let name = (preset.modelFileName as NSString).deletingPathExtension
102→        let ext = (preset.modelFileName as NSString).pathExtension
103→        if let bundledURL = Bundle.main.url(forResource: name, withExtension: ext) {
104→            logger.debug("Found model in bundle: \(preset.modelFileName)")
105→            return bundledURL
106→        }
107→
108→        logger.warning("Model not found: \(preset.modelFileName)")
109→        throw ModelError.notFound(preset)
110→    }
111→
112→    /// Whether the model for this preset is available (cached or bundled).
113→    func isAvailable(_ preset: WhisperModelPreset) -> Bool {
114→        (try? modelURL(for: preset)) != nil
115→    }
116→
117→    /// Downloads the model for the given preset from the Hugging Face whisper.cpp repository.
118→    /// Progress is published via `downloadProgress` and `downloadingPresets`.
119→    func downloadModel(_ preset: WhisperModelPreset) async throws {
120→        guard !downloadingPresets.contains(preset) else { return }
121→
122→        let baseURL = "https://huggingface.co/ggerganov/whisper.cpp/resolve/main/"
123→        guard let url = URL(string: baseURL + preset.modelFileName) else { return }
124→
125→        downloadingPresets.insert(preset)
126→        downloadProgress[preset] = 0
127→        defer {
128→            downloadingPresets.remove(preset)
129→            downloadProgress.removeValue(forKey: preset)
130→        }
131→
132→        let delegate = ModelDownloadDelegate { [weak self] progress in
133→            Task { @MainActor [weak self] in
134→                self?.downloadProgress[preset] = progress
135→            }
136→        }
137→
138→        do {
139→            let (tempURL, _) = try await URLSession.shared.download(from: url, delegate: delegate)
140→            let destination = modelsDirectory.appendingPathComponent(preset.modelFileName)
141→            if fileManager.fileExists(atPath: destination.path) {
142→                try fileManager.removeItem(at: destination)
143→            }
144→            try fileManager.moveItem(at: tempURL, to: destination)
145→            logger.info("Model downloaded: \(preset.modelFileName)")
146→        } catch {
147→            logger.error("Model download failed for \(preset.modelFileName): \(error.localizedDescription)")
148→            throw ModelError.downloadFailed(error.localizedDescription)
149→        }
150→    }
151→}
152→
153→// MARK: - ModelDownloadDelegate
154→
155→private final class ModelDownloadDelegate: NSObject, URLSessionDownloadDelegate {
156→    private let onProgress: @Sendable (Double) -> Void
157→
158→    init(onProgress: @escaping @Sendable (Double) -> Void) {
159→        self.onProgress = onProgress
160→    }
161→
162→    /// Required by URLSessionDownloadDelegate.
163→    /// The async/await wrapper owns the temp file — this is intentionally a no-op.
164→    func urlSession(_: URLSession, downloadTask _: URLSessionDownloadTask, didFinishDownloadingTo _: URL) {}
165→
166→    func urlSession(
167→        _: URLSession,
168→        downloadTask _: URLSessionDownloadTask,
169→        didWriteData _: Int64,
170→        totalBytesWritten: Int64,
171→        totalBytesExpectedToWrite: Int64
172→    ) {
173→        guard totalBytesExpectedToWrite > 0 else { return }
174→        onProgress(Double(totalBytesWritten) / Double(totalBytesExpectedToWrite))
175→    }
176→}
