import SwiftUI

/// Main view — authenticates, then shows four-tab navigation.
struct ContentView: View {
    @State private var authVM = AuthViewModel()
    @State private var sessionVM = SessionViewModel()
    @State private var recordingVM = RecordingViewModel()
    @State private var uploadVM = UploadViewModel()
    @State private var patientVM = PatientViewModel()
    @State private var transcriptionVM = TranscriptionViewModel()
    @State private var viewingTranscript: TranscriptViewerItem?
    @State private var selectedTab = 0

    var body: some View {
        Group {
            switch authVM.authState {
            case .unauthenticated, .authenticating, .tokenExpired:
                LoginView(authViewModel: authVM)
                    .frame(minWidth: 500, minHeight: 600)

            case .authenticated:
                authenticatedContent
            }
        }
        .background(Color.pabloCream)
        .preferredColorScheme(.light)
    }

    private var authenticatedContent: some View {
        TabView(selection: $selectedTab) {
            todayTab
            sessionsTab
            patientsTab
            settingsTab
        }
        .frame(minWidth: 500, minHeight: 600)
        .task { await configureAndLoad() }
        .alert("Recording Error", isPresented: $recordingVM.showError, presenting: recordingVM.errorMessage) { _ in
            Button("OK") {}
        } message: { message in
            Text(message)
        }
        .alert("Upload Error", isPresented: $uploadVM.showError, presenting: uploadVM.errorMessage) { _ in
            Button("OK") {}
        } message: { message in
            Text(message)
        }
        .alert("Patient Error", isPresented: $patientVM.showError, presenting: patientVM.errorMessage) { _ in
            Button("OK") {}
        } message: { message in
            Text(message)
        }
        .alert("Session Error", isPresented: $sessionVM.showError, presenting: sessionVM.errorMessage) { _ in
            Button("OK") {}
        } message: { message in
            Text(message)
        }
        .onChange(of: uploadVM.backendURL) { _, newURL in
            patientVM.backendURL = newURL
            sessionVM.backendURL = newURL
        }
    }

    // MARK: - Setup

    private func configureAndLoad() async {
        let serverURL = KeychainManager.getToken(forKey: .authServerURL)
            ?? authVM.authServerURL
        if let config = try? await fetchServerConfig(authServerURL: serverURL) {
            uploadVM.backendURL = config.apiUrl
            patientVM.backendURL = config.apiUrl
            sessionVM.backendURL = config.apiUrl
            if KeychainManager.getToken(forKey: .firebaseAPIKey) == nil {
                if let key = config.firebaseApiKey, !key.isEmpty {
                    KeychainManager.saveToken(key, forKey: .firebaseAPIKey)
                }
            }
        }

        uploadVM.configureAuth { [authVM] in try await authVM.getValidToken() }
        patientVM.configureAuth { [authVM] in try await authVM.getValidToken() }
        sessionVM.configureAuth { [authVM] in try await authVM.getValidToken() }

        do {
            _ = try await authVM.getValidToken()
        } catch {
            authVM.signOut()
        }

        await patientVM.loadPatients()
        await recordingVM.loadAudioSources()
        await uploadVM.checkBackendHealth()

        transcriptionVM.backendURL = uploadVM.backendURL
        transcriptionVM.configureAuth { [authVM] in try await authVM.getValidToken() }
        await transcriptionVM.retryPendingUploads()
    }

    // MARK: - Session orchestration

    private func startSession(_ session: Session) {
        Task {
            guard await sessionVM.startSession(session.id) != nil else { return }
            await recordingVM.startRecording()
            VideoLaunchService.launch(session: session)
        }
    }

    private func handleQuickStart(_ patient: Patient) {
        Task {
            guard await sessionVM.createAdHocSession(patientId: patient.id) != nil else { return }
            await recordingVM.startRecording()
        }
    }

    // MARK: - Tabs

    private var todayTab: some View {
        DayView(
            sessionVM: sessionVM,
            patients: patientVM.patients,
            isLoadingPatients: patientVM.isLoading,
            patientSearchText: $patientVM.searchText,
            recordingState: recordingVM.recordingState,
            recordingDuration: recordingVM.duration,
            onStartSession: { startSession($0) },
            onQuickStart: { handleQuickStart($0) },
            onStopRecording: { Task { await recordingVM.stopRecording() } }
        )
        .tabItem { Label("Today", systemImage: "calendar") }
        .tag(0)
    }

    private var sessionsTab: some View {
        SessionHistoryView(viewModel: sessionVM)
            .tabItem { Label("Sessions", systemImage: "list.clipboard") }
            .tag(1)
    }

    private var patientsTab: some View {
        PatientListView(viewModel: patientVM)
            .tabItem { Label("Patients", systemImage: "person.2") }
            .tag(2)
    }

    private var settingsTab: some View {
        SettingsView(
            backendURL: $uploadVM.backendURL,
            authServerURL: $authVM.authServerURL,
            selectedMicID: $recordingVM.selectedMicID,
            encryptionEnabled: $recordingVM.encryptionEnabled,
            debugEnableMic: $recordingVM.debugEnableMic,
            debugEnableSystem: $recordingVM.debugEnableSystem,
            userEmail: authVM.authenticatedEmail,
            availableMics: recordingVM.availableMics,
            isBackendReachable: uploadVM.isBackendReachable,
            bluetoothRoutingConflict: recordingVM.bluetoothRoutingConflict,
            bluetoothRecommendation: recordingVM.bluetoothRecommendation,
            systemAudioPermitted: recordingVM.systemAudioPermitted,
            recordingState: recordingVM.recordingState,
            diagnostics: recordingVM.debugDiagnostics,
            onCheckHealth: { Task { await uploadVM.checkBackendHealth() } },
            onGenerateTestTone: { recordingVM.generateTestTone() },
            onSignOut: { authVM.signOut() }
        )
        .tabItem { Label("Settings", systemImage: "gear") }
        .tag(3)
    }
}

import Foundation
import os

/// ViewModel for session management — powers the day view, session history, and session lifecycle.
///
/// Provides today's sessions, paginated session history, ad-hoc session creation,
/// and session status transitions.
/// Wired to the Rust API client via APIClient (thin wrapper over UniFFI).
@MainActor
@Observable
final class SessionViewModel {
    // MARK: - Published state (today)

    /// Today's scheduled sessions, refreshed by `loadTodaySessions()`.
    var todaySessions: [Session] = []

    /// Whether a data load is in progress.
    var isLoading = false

    /// User-facing error message (set on failure, cleared on next success).
    var errorMessage: String?
    var showError = false

    // MARK: - Published state (session history)

    /// All sessions (paginated), refreshed by `loadSessions()`.
    var sessions: [Session] = []

    /// Total number of sessions matching the current filter.
    var totalSessions: UInt32 = 0

    /// Current page for paginated session fetching.
    var currentPage = 1

    /// Whether more sessions are available beyond the current page.
    var hasMoreSessions = false

    /// Optional status filter for session history (nil = all statuses).
    var statusFilter: String? {
        didSet { Task { await loadSessions() } }
    }

    /// Whether a session history load is in progress (separate from today's loading).
    var isLoadingSessions = false

    // MARK: - Dependencies

    /// Set by ContentView after discovering the backend URL.
    var backendURL = "http://localhost:8000" {
        didSet {
            if URLValidator.validateScheme(backendURL) == nil {
                let token = apiClient.getToken
                apiClient = APIClient(baseURL: backendURL)
                apiClient.getToken = token
            }
        }
    }

    private var apiClient: APIClient
    private let logger = Logger(subsystem: AppConstants.appBundleID, category: "SessionViewModel")

    init() {
        self.apiClient = APIClient()
    }

    // MARK: - Auth

    /// Configures the API client with a token provider for authenticated requests.
    func configureAuth(getToken: @escaping @Sendable () async throws -> String) {
        apiClient.getToken = getToken
    }

    // MARK: - Today's sessions

    /// Fetches today's sessions from the backend.
    func loadTodaySessions() async {
        isLoading = true
        errorMessage = nil

        do {
            let timezone = TimeZone.current.identifier
            todaySessions = try await apiClient.fetchTodaySessions(timezone: timezone)
            logger.info("Loaded \(self.todaySessions.count) sessions for today")
        } catch {
            errorMessage = error.localizedDescription
            logger.error("Failed to load today's sessions: \(error.localizedDescription)")
        }

        isLoading = false
    }

    // MARK: - Ad-hoc session creation

    /// Creates a new ad-hoc session for the given patient and starts it immediately.
    /// Used by the "Quick Start" flow.
    func createAdHocSession(patientId: String) async -> Session? {
        isLoading = true
        errorMessage = nil

        do {
            let request = CreateSessionRequest(
                patientId: patientId,
                scheduledAt: ISO8601DateFormatter().string(from: Date()),
                durationMinutes: 50,
                videoLink: nil,
                videoPlatform: nil,
                sessionType: .individual,
                source: .companion,
                notes: nil
            )
            let session = try await apiClient.createSession(request: request)
            logger.info("Created ad-hoc session: \(session.id)")

            // Refresh today's list to include the new session
            await loadTodaySessions()

            isLoading = false
            return session
        } catch {
            errorMessage = error.localizedDescription
            showError = true
            logger.error("Failed to create ad-hoc session: \(error.localizedDescription)")
            isLoading = false
            return nil
        }
    }

    // MARK: - Session lifecycle

    /// Transitions a session to "in_progress" — called when the therapist clicks "Start Session".
    func startSession(_ sessionId: String) async -> Session? {
        do {
            let session = try await apiClient.updateSessionStatus(
                sessionId: sessionId,
                status: .inProgress
            )
            updateLocal(session)
            logger.info("Started session \(sessionId)")
            return session
        } catch {
            errorMessage = error.localizedDescription
            showError = true
            logger.error("Failed to start session \(sessionId): \(error.localizedDescription)")
            return nil
        }
    }

    /// Transitions a session to "recording_complete" — called when recording stops.
    func endSession(_ sessionId: String) async -> Session? {
        do {
            let session = try await apiClient.updateSessionStatus(
                sessionId: sessionId,
                status: .recordingComplete
            )
            updateLocal(session)
            logger.info("Ended session \(sessionId)")
            return session
        } catch {
            errorMessage = error.localizedDescription
            showError = true
            logger.error("Failed to end session \(sessionId): \(error.localizedDescription)")
            return nil
        }
    }

    // MARK: - Session history

    /// Fetches the first page of sessions from the backend, replacing the current list.
    func loadSessions() async {
        isLoadingSessions = true
        currentPage = 1
        errorMessage = nil

        do {
            let response = try await apiClient.fetchSessions(
                page: currentPage,
                pageSize: 20,
                status: statusFilter
            )
            sessions = response.data
            totalSessions = response.total
            hasMoreSessions = response.hasMore
            logger.info("Loaded \(response.data.count) of \(response.total) sessions")
        } catch {
            errorMessage = error.localizedDescription
            logger.error("Failed to load sessions: \(error.localizedDescription)")
        }

        isLoadingSessions = false
    }

    /// Fetches the next page of sessions and appends them to the current list.
    func loadMoreSessions() async {
        guard hasMoreSessions, !isLoadingSessions else { return }
        isLoadingSessions = true
        currentPage += 1

        do {
            let response = try await apiClient.fetchSessions(
                page: currentPage,
                pageSize: 20,
                status: statusFilter
            )
            sessions.append(contentsOf: response.data)
            totalSessions = response.total
            hasMoreSessions = response.hasMore
            logger.info("Loaded page \(self.currentPage): \(response.data.count) more sessions")
        } catch {
            currentPage -= 1
            errorMessage = error.localizedDescription
            logger.error("Failed to load more sessions: \(error.localizedDescription)")
        }

        isLoadingSessions = false
    }

    // MARK: - Private helpers

    /// Updates the local todaySessions array with the latest server state.
    private func updateLocal(_ session: Session) {
        if let index = todaySessions.firstIndex(where: { $0.id == session.id }) {
            todaySessions[index] = session
        }
    }
}

