 52→    let logger = Logger(
 53→        subsystem: "com.audiocapturekit",
 54→        category: "CompositeCaptureSession"
 55→    )
 56→
 57→    /// Creates a new composite capture session.
 58→    /// - Parameter configuration: Initial configuration. Can be updated via ``configure(_:)``.
 59→    public init(configuration: CaptureConfiguration) {
 60→        self.sessionState = UnfairLock(SessionState(configuration: configuration))
 61→        self.micCapture = AVFoundationMicCapture(deviceID: configuration.micDeviceID)
 62→        self.systemCapture = CoreAudioTapCapture()
