 75→    func setLevels(_ levels: AudioLevels) {
 76→        let delegate: (any AudioCaptureDelegate)? = sessionState.withLock {
 77→            $0.currentLevels = levels
 78→            return $0.delegate
 79→        }
 80→
 81→        delegate?.captureSession(self, didUpdateLevels: levels)
 82→    }
