 84→    func elapsedDuration() -> TimeInterval {
 85→        sessionState.withLock { state in
 86→            guard let startTime = state.captureStartTime else { return 0 }
 87→            let totalElapsed = Date().timeIntervalSince(startTime)
 88→            let currentPauseDuration: TimeInterval = if let pauseTime = state.lastPauseTime {
 89→                Date().timeIntervalSince(pauseTime)
 90→            } else {
 91→                0
 92→            }
 93→            return totalElapsed - state.pausedDuration - currentPauseDuration
