174→    public func pauseCapture() throws {
175→        let currentState = sessionState.withLock { $0.state }
176→        guard case .capturing = currentState else {
177→            throw CaptureError.configurationFailed("Cannot pause when not capturing")
178→        }
179→
180→        sessionState.withLock { $0.lastPauseTime = Date() }
181→        let elapsed = elapsedDuration()
182→        setState(.paused(duration: elapsed))
183→    }
184→
185→    public func resumeCapture() throws {
186→        let currentState = sessionState.withLock { $0.state }
187→        guard case .paused = currentState else {
188→            throw CaptureError.configurationFailed("Cannot resume when not paused")
189→        }
190→
191→        sessionState.withLock { state in
192→            if let pauseTime = state.lastPauseTime {
193→                state.pausedDuration += Date().timeIntervalSince(pauseTime)
194→            }
195→            state.lastPauseTime = nil
