 29→        processingTask = Task { [weak self] in
 30→            while !Task.isCancelled {
 31→                try? await Task.sleep(nanoseconds: 100_000_000)
 32→                guard let self, !Task.isCancelled else { break }
 33→
 34→                let currentState = sessionState.withLock { $0.state }
