249→                actualSampleRate: actualRate,
250→                channels: UInt16(configuration.channels),
251→                bitDepth: UInt16(configuration.bitDepth)
252→            )
253→        } catch {
254→            setState(.failed(.storageError("Failed to close file")))
255→            throw error
256→        }
257→
258→        let rawPCMURLs: [URL] = sessionState.withLock {
259→            $0.micPCMFileHandle?.closeFile()
260→            $0.micPCMFileHandle = nil
261→            $0.systemPCMFileHandle?.closeFile()
262→            $0.systemPCMFileHandle = nil
263→            return $0.rawPCMFileURLs
264→        }
265→
266→        let result = buildRecordingResult(checksum: checksum, rawPCMFileURLs: rawPCMURLs)
267→        setState(.completed(result))
268→
269→        let delegate = sessionState.withLock { $0.delegate }
270→        delegate?.captureSession(self, didFinishCapture: result)
271→        return result
272→    }
273→
274→    private func buildRecordingResult(checksum: String, rawPCMFileURLs: [URL] = []) -> RecordingResult {
275→        let duration = elapsedDuration()
276→        let config = configuration
277→        let fileURL: URL = sessionState.withLock { $0.fileURL! }
278→
279→        let (tracks, channelLayout): ([AudioTrack], ChannelLayout)
280→        switch config.mixingStrategy {
281→        case .separated, .multichannel:
282→            tracks = [
283→                AudioTrack(type: .mic, channel: .left, label: "Mic (Local)"),
284→                AudioTrack(type: .system, channel: .right, label: "System (Remote, mono-fold)"),
285→            ]
286→            channelLayout = .separatedStereo
287→        case .blended:
288→            tracks = [
289→                AudioTrack(type: .mic, channel: .center),
290→                AudioTrack(type: .system, channel: .stereo),
291→            ]
292→            channelLayout = .blended
293→        }
294→
295→        let metadata = RecordingMetadata(
296→            duration: duration,
297→            fileURL: fileURL,
298→            checksum: checksum,
299→            isEncrypted: config.encryptor != nil,
300→            tracks: tracks,
301→            encryptionAlgorithm: config.encryptor?.algorithm,
302→            encryptionKeyId: config.encryptor?.keyMetadata()["keyId"],
303→            channelLayout: channelLayout
304→        )
305→
306→        return RecordingResult(
307→            fileURL: fileURL,
308→            duration: duration,
309→            metadata: metadata,
310→            checksum: checksum,
311→            rawPCMFileURLs: rawPCMFileURLs
312→        )
313→    }
314→}
