179→    public func pauseCapture() throws {
180→        let currentState = sessionState.withLock { $0.state }
181→        guard case .capturing = currentState else {
182→            throw CaptureError.configurationFailed("Cannot pause when not capturing")
183→        }
184→
185→        sessionState.withLock { $0.lastPauseTime = Date() }
186→        let elapsed = elapsedDuration()
