/// ``AVFoundationMicCapture`` (microphone, left channel), mixing them into stereo
/// PCM and writing the result to an optionally encrypted WAV file.
///
/// ## State Machine
/// ```
/// idle -> configuring -> ready -> capturing <-> paused
///                                    |              |
///                                    v              v
///                                 stopping -> completed
///                                    |
///                                    v
///                                  failed
/// ```
public final class CompositeCaptureSession: @unchecked Sendable {
    struct SessionState {
        var state: CaptureState = .idle
        var delegate: (any AudioCaptureDelegate)?
        var configuration: CaptureConfiguration
        var currentLevels: AudioLevels = .zero
        var captureStartTime: Date?
        var pausedDuration: TimeInterval = 0
        var lastPauseTime: Date?
        var fileURL: URL?
        var diagnostics = CaptureSessionDiagnostics()
        /// Actual mic sample rate detected from the first callback (may differ from config).
        var detectedMicRate: Double?
        var micPCMFileHandle: FileHandle?
        var systemPCMFileHandle: FileHandle?
        var rawPCMFileURLs: [URL] = []
    }

    let sessionState: UnfairLock<SessionState>

    let micCapture: AVFoundationMicCapture
    let systemCapture: CoreAudioTapCapture
    var stereoMixer: StereoMixer

    var fileWriter: EncryptedFileWriter?
    var micBuffer: AudioBufferManager?
    var systemBuffer: AudioBufferManager?

    var durationTimer: Task<Void, Never>?

    /// Dedicated queue for audio processing (mixing, conversion, file writes).
    /// Replaces the previous Task.sleep polling loop — processing is now triggered
    /// directly by audio callbacks when the ring buffer crosses a threshold.
    let processingQueue = DispatchQueue(label: "com.audiocapturekit.processing")

    /// Dedicated queue for PCM sidecar file writes — keeps disk I/O off the processing path.
    let pcmWriteQueue = DispatchQueue(label: "com.audiocapturekit.pcm-io")

    /// Threshold in samples — when the mic buffer reaches this count, processing is dispatched.
    /// Set to 1 second of audio (configured in startCapture).
    var processingThreshold: Int = 48000

    /// Flag to prevent multiple concurrent processBuffers dispatches.
    let processingScheduled = UnfairLock(false)

    let logger = Logger(
        subsystem: "com.audiocapturekit",
        category: "CompositeCaptureSession"
    )

    /// Creates a new composite capture session.
